mapper.select:
SELECT tm.message_id, tm.student_id, stu.real_name AS student_name, tm.from_role, CASE tm.from_role WHEN 'parent' THEN '家长' WHEN 'student' THEN '学生' WHEN 'leader' THEN '领导' ELSE '用户' END AS from_role_text, tm.content, DATE_FORMAT(tm.created_at, '%Y-%m-%d %H:%i') AS time_text, tm.is_read, tm.replied, tm.reply_content FROM teacher_message tm LEFT JOIN user stu ON tm.student_id = stu.user_id WHERE tm.receiver_id = #{receiverId}
AND tm.is_read = 0
ORDER BY tm.created_at DESC
